class ContentRange {
  ContentRange(this.start, this.end, this.total) {
    if (start < 0 || end < start || end >= total) {
      throw FormatException('invalid content range');
    }
  }

  final int start;
  final int end;
  final int total;

  int get length => end - start;

  factory ContentRange.parse(String value) {
    final match = RegExp(r'^bytes (\d+)-(\d+)/(\d+)$').firstMatch(value);
    if (match == null) throw FormatException('bad Content-Range');
    return ContentRange(
      int.parse(match.group(1)!),
      int.parse(match.group(2)!),
      int.parse(match.group(3)!),
    );
  }
}

