import 'content_range.dart';

class ChunkLedger {
  ChunkLedger(this.total);

  final int total;
  final List<ContentRange> _ranges = [];

  bool accept(ContentRange range) {
    if (range.total != total) return false;
    for (final existing in _ranges) {
      final separated = range.end < existing.start - 1 ||
          range.start > existing.end + 1;
      if (!separated) return false;
    }
    _ranges.add(range);
    return true;
  }

  bool get isComplete {
    if (_ranges.isEmpty) return false;
    final ordered = [..._ranges]..sort((a, b) => a.start.compareTo(b.start));
    var next = 0;
    for (final range in ordered) {
      if (range.start != next) return false;
      next += range.length;
    }
    return next == total;
  }
}

