List<int> assembleChunks(Map<int, List<int>> chunks, int total) {
  final offsets = chunks.keys.toList()
    ..sort((a, b) => a.toString().compareTo(b.toString()));
  final output = <int>[];
  for (final offset in offsets) {
    output.addAll(chunks[offset]!);
  }
  if (output.length != total) {
    throw StateError('assembled length does not match upload');
  }
  return output;
}

