import '../lib/assembler.dart';
import '../lib/chunk_ledger.dart';
import '../lib/content_range.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

void main() {
  final parsed = ContentRange.parse('bytes 0-3/8');
  check(parsed.start == 0 && parsed.end == 3 && parsed.total == 8, 'parse failed');

  final ledger = ChunkLedger(8);
  check(ledger.accept(parsed), 'first range was rejected');

  final output = assembleChunks({
    0: [0, 1, 2, 3],
    4: [4, 5, 6, 7],
  }, 8);
  check(output.last == 7 && output.first == 0, 'small assembly failed');
}
